/// Visual state for [BTSwitchField].
enum BTSwitchFieldState {
  off,
  on,
  disabledOff,
  disabledOn,
  errorOff,
  errorOn,
}

/// Visual size of [BTSwitchField].
///
/// - [md] — Default (40×20 dp track, 18×12 dp thumb).
/// - [sm] — Small (24×12 dp track, 10×8 dp thumb).
enum BTSwitchFieldSize { md, sm }

// BTSwitchField — Figma 504:8352 + 504:8234
import 'package:btech_tokens/btech_tokens.dart';
import 'package:btech_ui/src/components/atoms/switch_field/switch_field.types.dart';
import 'package:flutter/material.dart';

/// A toggle switch atom with animated track + thumb.
///
/// ```dart
/// // Right label (default)
/// BTSwitch(
///   value: _on,
///   onChanged: (v) => setState(() => _on = v),
///   labelRight: 'Enable notifications',
/// )
///
/// // Both sides
/// BTSwitch(
///   value: _on,
///   onChanged: _onChanged,
///   labelLeft: 'Auto-save',
///   labelRight: 'Enabled',
/// )
///
/// // With subtext + error
/// BTSwitch(
///   value: false,
///   error: true,
///   labelRight: 'Notifications',
///   subtextRight: 'Required field',
///   onChanged: _onChanged,
/// )
///
/// // Inner text inside the track
/// BTSwitch(
///   value: _on,
///   onChanged: _onChanged,
///   innerText: 'ON',
/// )
///
/// // Small size
/// BTSwitchField(
///   value: _on,
///   size: BTSwitchFieldSize.sm,
///   onChanged: _onChanged,
///   labelRight: 'Small switch',
/// )
/// ```
class BTSwitchField extends StatefulWidget {
  const BTSwitchField({
    required this.value,
    this.onChanged,
    this.disabled = false,
    this.error = false,
    this.size = BTSwitchFieldSize.md,
    this.labelLeft,
    this.subtextLeft,
    this.labelRight,
    this.subtextRight,
    this.innerText,
    super.key,
  });

  /// Whether the switch is on.
  final bool value;

  /// Called when the user taps the switch. Not called when [disabled] is true.
  final ValueChanged<bool>? onChanged;

  /// Disables all user interaction.
  final bool disabled;

  /// Applies the error (red) track colour.
  final bool error;

  /// Label text to the left of the track.
  final String? labelLeft;

  /// Supporting text below [labelLeft]. In error state renders in red.
  final String? subtextLeft;

  /// Label text to the right of the track.
  final String? labelRight;

  /// Supporting text below [labelRight]. In error state renders in red.
  final String? subtextRight;

  /// Visual size of the switch. Defaults to [BTSwitchFieldSize.md].
  final BTSwitchFieldSize size;

  /// Short text shown inside the track pill (e.g. 'ON', 'OK').
  /// When set the track becomes content-sized and the thumb swaps
  /// sides with the text instead of sliding.
  final String? innerText;

  @override
  State<BTSwitchField> createState() => _BTSwitchFieldState();
}

class _BTSwitchFieldState extends State<BTSwitchField>
    with SingleTickerProviderStateMixin {
  late final AnimationController _controller;
  late final Animation<double> _thumbSlide;

  BTSwitchFieldState get _state {
    if (widget.disabled) {
      return widget.value
          ? BTSwitchFieldState.disabledOn
          : BTSwitchFieldState.disabledOff;
    }
    if (widget.error) {
      return widget.value
          ? BTSwitchFieldState.errorOn
          : BTSwitchFieldState.errorOff;
    }
    return widget.value ? BTSwitchFieldState.on : BTSwitchFieldState.off;
  }

  @override
  void initState() {
    super.initState();
    _controller = AnimationController(
      vsync: this,
      duration: const Duration(milliseconds: 150),
      value: widget.value ? 1.0 : 0.0,
    );
    _thumbSlide = CurvedAnimation(
      parent: _controller,
      curve: Curves.easeInOut,
    );
  }

  @override
  void didUpdateWidget(BTSwitchField old) {
    super.didUpdateWidget(old);
    if (old.value != widget.value) {
      widget.value ? _controller.forward() : _controller.reverse();
    }
  }

  @override
  void dispose() {
    _controller.dispose();
    super.dispose();
  }

  void _handleTap() {
    if (!widget.disabled) {
      widget.onChanged?.call(!widget.value);
    }
  }

  @override
  Widget build(BuildContext context) {
    final colors = context.btColor;
    final state = _state;

    final Widget track = widget.innerText != null
        ? _BTSwitchInnerTrack(
            value: widget.value,
            state: state,
            colors: colors,
            innerText: widget.innerText!,
            size: widget.size,
          )
        : _BTSwitchTrack(
            state: state,
            slide: _thumbSlide,
            colors: colors,
            size: widget.size,
          );

    Widget? leftText;
    Widget? rightText;

    if (widget.labelLeft != null || widget.subtextLeft != null) {
      leftText = _BTSwitchText(
        label: widget.labelLeft,
        subtext: widget.subtextLeft,
        state: state,
        colors: colors,
      );
    }
    if (widget.labelRight != null || widget.subtextRight != null) {
      rightText = _BTSwitchText(
        label: widget.labelRight,
        subtext: widget.subtextRight,
        state: state,
        colors: colors,
      );
    }

    final children = <Widget>[
      if (leftText != null) ...[leftText, SizedBox(width: 8.0)],
      track,
      if (rightText != null) ...[SizedBox(width: 8.0), rightText],
    ];

    return MouseRegion(
      cursor: widget.disabled
          ? SystemMouseCursors.forbidden
          : SystemMouseCursors.click,
      child: GestureDetector(
        onTap: _handleTap,
        child: Row(
          mainAxisSize: MainAxisSize.min,
          crossAxisAlignment: CrossAxisAlignment.start,
          children: children,
        ),
      ),
    );
  }
}

// ── Track (default — animated sliding thumb) ──────────────────

class _BTSwitchTrack extends StatelessWidget {
  const _BTSwitchTrack({
    required this.state,
    required this.slide,
    required this.colors,
    required this.size,
  });

  final BTSwitchFieldState state;
  final Animation<double> slide;
  final BTColorTheme colors;
  final BTSwitchFieldSize size;

  Color get _trackColor {
    switch (state) {
      case BTSwitchFieldState.on:
        return colors.brand.primary;
      case BTSwitchFieldState.disabledOff:
      case BTSwitchFieldState.disabledOn:
        return colors.bg.subtlest;
      case BTSwitchFieldState.errorOff:
      case BTSwitchFieldState.errorOn:
        return colors.ext.error;
      case BTSwitchFieldState.off:
        return colors.bg.tertiary;
    }
  }

  @override
  Widget build(BuildContext context) {
    // md: 40×20 dp, padding 4 dp, thumb 18×12 dp, travel 14 dp.
    // sm: 24×12 dp, padding 2 dp, thumb 10×8 dp, travel 10 dp.
    final trackW = size == BTSwitchFieldSize.md ? 40.0 : 24.0;
    final trackH = size == BTSwitchFieldSize.md ? 20.0 : 12.0;
    final padding = size == BTSwitchFieldSize.md ? 4.0 : 2.0;
    final thumbW = size == BTSwitchFieldSize.md ? 18.0 : 10.0;
    final thumbH = size == BTSwitchFieldSize.md ? 12.0 : 8.0;
    final travel = trackW - padding * 2 - thumbW;

    return Padding(
      padding: EdgeInsets.only(top: 2.0), // align track centre with label
      child: AnimatedContainer(
        duration: const Duration(milliseconds: 150),
        width: trackW,
        height: trackH,
        decoration: BoxDecoration(
          color: _trackColor,
          borderRadius: BorderRadius.circular(9999),
        ),
        padding: EdgeInsets.all(padding),
        child: AnimatedBuilder(
          animation: slide,
          builder: (_, __) => Stack(
            children: [
              Positioned(
                left: slide.value * travel,
                top: 0,
                child: Container(
                  width: thumbW,
                  height: thumbH,
                  decoration: BoxDecoration(
                    color: colors.bg.primary,
                    borderRadius: BorderRadius.circular(9999),
                  ),
                ),
              ),
            ],
          ),
        ),
      ),
    );
  }
}

// ── Track (inner text variant — direction flip, no slide) ──────

class _BTSwitchInnerTrack extends StatelessWidget {
  const _BTSwitchInnerTrack({
    required this.value,
    required this.state,
    required this.colors,
    required this.innerText,
    required this.size,
  });

  final bool value;
  final BTSwitchFieldState state;
  final BTColorTheme colors;
  final String innerText;
  final BTSwitchFieldSize size;

  Color get _trackColor {
    switch (state) {
      case BTSwitchFieldState.on:
        return colors.brand.primary;
      case BTSwitchFieldState.disabledOff:
      case BTSwitchFieldState.disabledOn:
        return colors.bg.subtlest;
      case BTSwitchFieldState.errorOff:
      case BTSwitchFieldState.errorOn:
        return colors.ext.error;
      case BTSwitchFieldState.off:
        return colors.bg.tertiary;
    }
  }

  @override
  Widget build(BuildContext context) {
    // md: thumb 18×12 dp, track height 20 dp, font 10 dp.
    //     Off padding: l=4, r=8  |  On padding: l=8, r=4
    //     (outer 2dp top+bottom, inner for thumb side / text side)
    // sm: thumb 12×8 dp, track height 12 dp, font 8 dp.
    //     Off padding: l=2, r=4  |  On padding: l=4, r=2
    final thumbW = size == BTSwitchFieldSize.md ? 18.0 : 12.0;
    final thumbH = size == BTSwitchFieldSize.md ? 12.0 : 8.0;
    final trackH = size == BTSwitchFieldSize.md ? 20.0 : 12.0;
    final innerFontSize = size == BTSwitchFieldSize.md ? 10.0 : 8.0;
    final paddingTop = size == BTSwitchFieldSize.md ? 2.0 : 0.0;
    final paddingBottom = size == BTSwitchFieldSize.md ? 2.0 : 0.0;
    // off: [thumb][gap][text] — thumb side has smaller padding
    final paddingThumbSide = size == BTSwitchFieldSize.md ? 4.0 : 2.0;
    final paddingTextSide = size == BTSwitchFieldSize.md ? 8.0 : 4.0;

    final thumb = Container(
      width: thumbW,
      height: thumbH,
      decoration: BoxDecoration(
        color: colors.bg.primary,
        borderRadius: BorderRadius.circular(9999),
      ),
    );

    final label = Text(
      innerText,
      style: TextStyle(
        fontFamily: BTTypography.fontFamily,
        fontSize: innerFontSize,
        fontWeight: FontWeight.w500,
        height: thumbH / innerFontSize,
        color: colors.text.inverse,
      ),
    );

    final children = value
        ? <Widget>[label, SizedBox(width: 4.0), thumb]
        : <Widget>[thumb, SizedBox(width: 4.0), label];

    return Padding(
      padding: EdgeInsets.only(top: 2.0),
      child: AnimatedContainer(
        duration: const Duration(milliseconds: 150),
        height: trackH,
        padding: EdgeInsetsDirectional.fromSTEB(
          value ? paddingTextSide : paddingThumbSide,
          paddingTop,
          value ? paddingThumbSide : paddingTextSide,
          paddingBottom,
        ),
        decoration: BoxDecoration(
          color: _trackColor,
          borderRadius: BorderRadius.circular(9999),
        ),
        child: Row(
          mainAxisSize: MainAxisSize.min,
          crossAxisAlignment: CrossAxisAlignment.center,
          children: children,
        ),
      ),
    );
  }
}

// ── Text (label + subtext) ─────────────────────────────────────

class _BTSwitchText extends StatelessWidget {
  const _BTSwitchText({
    required this.label,
    required this.subtext,
    required this.state,
    required this.colors,
  });

  final String? label;
  final String? subtext;
  final BTSwitchFieldState state;
  final BTColorTheme colors;

  bool get _disabled =>
      state == BTSwitchFieldState.disabledOff ||
      state == BTSwitchFieldState.disabledOn;

  bool get _error =>
      state == BTSwitchFieldState.errorOff ||
      state == BTSwitchFieldState.errorOn;

  @override
  Widget build(BuildContext context) {
    final labelColor =
        _disabled ? colors.text.disabled : colors.text.primary;
    final subtextColor = _disabled
        ? colors.text.disabled
        : _error
            ? colors.text.error
            : colors.text.secondary;

    return Column(
      mainAxisSize: MainAxisSize.min,
      crossAxisAlignment: CrossAxisAlignment.start,
      children: [
        if (label != null)
          Text(
            label!,
            style: TextStyle(
              fontFamily: BTTypography.fontFamily,
              fontSize: 14.0,
              fontWeight: FontWeight.w500,
              height: 16 / 14,
              color: labelColor,
            ),
          ),
        if (subtext != null) ...[
          SizedBox(height: 2.0),
          Text(
            subtext!,
            style: TextStyle(
              fontFamily: BTTypography.fontFamily,
              fontSize: 12.0,
              fontWeight: FontWeight.w400,
              height: 16 / 12,
              color: subtextColor,
            ),
          ),
        ],
      ],
    );
  }
}
